      \u0275\u0275elementStart(48, "p");
      \u0275\u0275text(49, 'The National Anthem of India "Jana Gana Mana", composed originally in Bengali by Rabindranath Tagore, was adopted in its Hindi version by the Constituent Assembly as the National Anthem of India on 24 January 1950. It was first sung on 27 December 1911 at the Calcutta Session of the Indian National Congress.');
