      \u0275\u0275element(74, "br");
      \u0275\u0275text(75, " \u0938\u0941\u0939\u093E\u0938\u093F\u0928\u0940\u0902 \u0938\u0941\u092E\u0927\u0941\u0930 \u092D\u093E\u0937\u093F\u0923\u0940\u092E\u094D,");
      \u0275\u0275element(76, "br");
